func TestVersionCompatiblePatchDifference(t *testing.T) {
	// Same major.minor with different patch should be accepted (semver compat).
	resp := sendRecv(t, `{"protocol_version":"0.1.99","id":1,"command":"handshake","capabilities":[]}`)
	if resp.Status != "handshake" {
		t.Errorf("status = %q, want handshake; patch-only difference should be compatible", resp.Status)
	}
}

func TestVersionIncompatibleMinorDifference(t *testing.T) {
	// Different minor version should be rejected.
	resp := sendRecv(t, `{"protocol_version":"0.2.0","id":1,"command":"handshake","capabilities":[]}`)
	if resp.Status != "error" {
		t.Errorf("status = %q, want error", resp.Status)
	}
	if resp.Code != ErrVersionMismatch {
		t.Errorf("code = %q, want version_mismatch", resp.Code)
	}
}

